#pragma OPENCL EXTENSION cl_khr_fp64 : enable

typedef struct {
    int value;
} record;

typedef struct {
    int location;
    int indices[DEFAULT_ORDER + 1];
    int keys[DEFAULT_ORDER + 1];
    int is_leaf; // bool as int
    int num_keys;
} knode;

__kernel void
kernel_cpu(  const int cores_arg,

            __global record *records,
            __global knode *knodes,
            const long knodes_elem,

            const int order,
            const long maxheight,
            const int count,

            __global long *currKnode,
            __global long *offset,
            __global int *keys,
            __global record *ans)
{
    // Each work-group handles one bid; each work-item in the group handles thid
    int bid = get_group_id(0);
    int thid = get_local_id(0);
    int threadsPerBlock = order < 1024 ? order : 1024;

    if (bid >= count) return;

    long curr = currKnode[bid];
    long off = offset[bid];
    int key = keys[bid];

    for (long i = 0; i < maxheight; i++) {
        barrier(CLK_LOCAL_MEM_FENCE);

        if (thid < threadsPerBlock) {
            int keys0 = knodes[curr].keys[thid];
            int keys1 = knodes[curr].keys[thid + 1];
            if (keys0 <= key && keys1 > key) {
                int idx = knodes[off].indices[thid];
                if (idx < knodes_elem) {
                    off = idx;
                }
            }
        }
        barrier(CLK_LOCAL_MEM_FENCE);

        curr = off;
    }

    barrier(CLK_LOCAL_MEM_FENCE);

    if (thid < threadsPerBlock) {
        int k = knodes[curr].keys[thid];
        if (k == key) {
            ans[bid].value = records[knodes[curr].indices[thid]].value;
        }
    }
}

