    int keys[DEFAULT_ORDER + 1];
    int is_leaf; // bool as int
    int num_keys;
} knode;

__kernel void
kernel_cpu_2(    const int cores_arg,

                __global knode *knodes,
                const long knodes_elem,

                const int order,
                const long maxheight,
                const int count,

                __global long *currKnode,
                __global long *offset,
                __global long *lastKnode,
                __global long *offset_2,
                __global int *start,
                __global int *end,
                __global int *recstart,
                __global int *reclength)
{
    int bid = get_group_id(0);
    int thid = get_local_id(0);
    int threadsPerBlock = order < 1024 ? order : 1024;

    if (bid >= count) return;

    long curr = currKnode[bid];
    long off = offset[bid];
    long last = lastKnode[bid];
    long off2 = offset_2[bid];
    int s = start[bid];
    int e = end[bid];

    for (long i = 0; i < maxheight; i++) {
        barrier(CLK_LOCAL_MEM_FENCE);

        if (thid < threadsPerBlock) {
            int ckey0 = knodes[curr].keys[thid];
            int ckey1 = knodes[curr].keys[thid + 1];
            if (ckey0 <= s && ckey1 > s) {
                int idx = knodes[curr].indices[thid];
                if (idx < knodes_elem) {
                    off = idx;
                }
            }

            int lkey0 = knodes[last].keys[thid];
            int lkey1 = knodes[last].keys[thid + 1];
            if (lkey0 <= e && lkey1 > e) {
                int idx = knodes[last].indices[thid];
                if (idx < knodes_elem) {
                    off2 = idx;
                }
            }
        }
        barrier(CLK_LOCAL_MEM_FENCE);

        curr = off;
        last = off2;
    }

    barrier(CLK_LOCAL_MEM_FENCE);

    if (thid < threadsPerBlock) {
        if (knodes[curr].keys[thid] == s) {
            recstart[bid] = knodes[curr].indices[thid];
        }
    }

    barrier(CLK_LOCAL_MEM_FENCE);

    if (thid < threadsPerBlock) {
        if (knodes[last].keys[thid] == e) {
            reclength[bid] = knodes[last].indices[thid] - recstart[bid] + 1;
        }
    }
}
